local G = DYCLegendary local require = G.DYCModRequire local TableContains = G.lib.TableContains local TableAdd = G.lib.TableAdd local TableRemoveValue = G.lib.TableRemoveValue local Spell = Class(function(self, data) data = data or {} self.name = data.name assert(self.name, "Spell name required!" ) self.name = string.lower(self.name) self.tasks = {} end) function Spell:Remove() for k, v in pairs(self.tasks) do if v ~= nil then v:Cancel() end end self.tasks = {} end function Spell:StartTask(dt, cb) local task = nil if cb == nil and dt ~= nil then task = GetWorld():DoPeriodicTask(FRAMES, dt) else task = GetWorld():DoPeriodicTask(dt, cb) end table.insert(self.tasks, task) return task end function Spell:StopTask(task) task = task or self.tasks[0x1] if task then task:Cancel() TableRemoveValue(self.tasks, task) if self.onStopTask then self.onStopTask(self, task) end end end function Spell:Cast(target, p) if self.onCast then self.target = target if target and not p then p = target:GetPosition() end self.dest = p self.onCast(self, target, p) end end function Spell:SetData(data) if self.onSetData then self.onSetData(self, data) end end return Spell 